// Category × Market compliance data
type Severity = "high" | "medium" | "low";

export interface ComplianceItem {
  name: string;
  required: boolean;
  desc: string;
  severity: Severity;
  action: string; // rectification advice
  estimatedTime: string;
  needsThirdParty: boolean;
}

// Category-level compliance requirements (cross-market)
interface CategoryCompliance {
  name: string;
  desc: string;
  items: ComplianceItem[];
}

